package ua.university.sms.service;
import org.springframework.stereotype.Service;import ua.university.sms.exception.NotFoundException;import ua.university.sms.model.dto.StudentDtos.*;import ua.university.sms.model.entity.*;import ua.university.sms.repository.*;import java.util.*;
@Service public class StudentService{private final StudentRepository repo;private final EnrollmentRepository enrollments;public StudentService(StudentRepository repo,EnrollmentRepository enrollments){this.repo=repo;this.enrollments=enrollments;}public Response create(Request request){Student s=new Student();apply(s,request);return toDto(repo.save(s));}public Response get(Long id){return toDto(find(id));}public List<Response> list(StudentStatus status,Integer year,String search){List<Student> data;if(search!=null&&!search.isBlank())data=repo.findByFullNameContainingIgnoreCaseOrEmailContainingIgnoreCase(search,search);else if(status!=null)data=repo.findByStatus(status);else if(year!=null)data=repo.findByYear(year);else data=repo.findAll();return data.stream().map(this::toDto).toList();}public Response update(Long id,Request request){Student s=find(id);apply(s,request);return toDto(repo.save(s));}public void delete(Long id){repo.delete(find(id));}public List<Response> unpaid(){return repo.findStudentsWithUnpaidCourses().stream().map(this::toDto).toList();}public List<Response> top(int limit){return repo.findAll().stream().map(this::toDto).sorted(Comparator.comparing(Response::gpa,Comparator.nullsLast(Comparator.reverseOrder()))).limit(limit).toList();}Student find(Long id){return repo.findById(id).orElseThrow(()->new NotFoundException("Student not found: "+id));}Double gpa(Long studentId){List<Double> grades=enrollments.findByStudentId(studentId).stream().map(Enrollment::getGrade).filter(Objects::nonNull).toList();return grades.isEmpty()?null:grades.stream().mapToDouble(Double::doubleValue).average().orElse(0);}private void apply(Student s,Request r){s.setFullName(r.fullName());s.setEmail(r.email());s.setYear(r.year());s.setStatus(r.status()==null?StudentStatus.ACTIVE:r.status());}private Response toDto(Student s){return new Response(s.getId(),s.getFullName(),s.getEmail(),s.getYear(),s.getStatus(),gpa(s.getId()));}}
